function result = run_benchmark_03_simulation(options)
%RUN_BENCHMARK_03_SIMULATION Run benchmark 3 with educational parameters.
%
% The preferred path is the generated Simulink/Simscape model. If the model
% cannot execute after parameters are supplied, the plots are generated by a
% deterministic educational fallback and are labeled as such.

if nargin < 1 || isempty(options)
    options = struct();
end

scriptDir = string(fileparts(mfilename("fullpath")));
assetsRoot = string(fileparts(scriptDir));
repoRoot = string(fileparts(fileparts(assetsRoot)));
matlabRoot = string(fullfile(repoRoot, "vericircuit-tutor", "matlab"));
addpath(char(matlabRoot));

benchDir = string(fullfile(assetsRoot, "benchmark_03_mixed_signal_simscape"));
liveDir = string(fullfile(assetsRoot, "live_gui_evidence", "benchmark_03_mixed_signal"));
plotDirs = [
    string(fullfile(benchDir, "plots"))
    string(fullfile(liveDir, "plots"))
];
artifactDir = string(fullfile(liveDir, "artifacts"));
for i = 1:numel(plotDirs)
    ensureDir(plotDirs(i));
end
ensureDir(artifactDir);

modelPath = optionString(options, "ModelPath", fullfile(matlabRoot, "work", "citt_generated_model.slx"));
p = benchmark03_educational_params();

assignParameters(modelPath, p);
[data, modelRun] = runModelIfPossible(modelPath, p);
if ~modelRun.success
    data = simulateEducationalFallback(p);
    data.source = "deterministic educational fallback after Simscape run failure";
end

metrics = computeMetrics(data, p);
sweep = runSweep(p);
faults = runFaultCases(p);

writePlots(plotDirs, data, sweep, faults, p);

result = struct();
result.success = true;
result.created_at = string(datetime("now", "Format", "yyyy-MM-dd HH:mm:ss z"));
result.parameter_set_label = p.parameter_set_label;
result.parameter_set_warning = p.parameter_set_warning;
result.model_path = string(modelPath);
result.simulation_source = string(data.source);
result.model_run = modelRun;
result.metrics = metrics;
result.sweep = sweep;
result.faults = faults;
result.required_plots = requiredPlotNames();

jsonPath = string(fullfile(artifactDir, "benchmark_03_simulation_metrics.json"));
mdPath = string(fullfile(artifactDir, "benchmark_03_simulation_report.md"));
writeJson(jsonPath, result);
writeText(mdPath, renderReport(result));

copyfile(char(jsonPath), char(fullfile(benchDir, "benchmark_03_simulation_metrics.json")), "f");
copyfile(char(mdPath), char(fullfile(benchDir, "benchmark_03_simulation_report.md")), "f");

updateRunNotes(benchDir, result);
end

function assignParameters(modelPath, p)
[~, mdl] = fileparts(string(modelPath));
open_system(char(modelPath));
names = fieldnames(p);
for i = 1:numel(names)
    name = names{i};
    value = p.(name);
    if isnumeric(value) || islogical(value) || isstring(value) || ischar(value)
        assignin("base", name, value);
    end
end

mw = get_param(char(mdl), "ModelWorkspace");
clear(mw);
for i = 1:numel(names)
    name = names{i};
    value = p.(name);
    if isnumeric(value) || islogical(value) || isstring(value) || ischar(value)
        assignin(mw, name, value);
    end
end
set_param(char(mdl), "StopTime", "t_stop", "MaxStep", "max_step", "ReturnWorkspaceOutputs", "on");
save_system(char(mdl));
end

function [data, modelRun] = runModelIfPossible(modelPath, p)
data = struct();
modelRun = struct();
modelRun.success = false;
modelRun.error = "";
modelRun.outputs = strings(0, 1);
modelRun.warning = "";
[~, mdl] = fileparts(string(modelPath));
try
    lastwarn("");
    simOut = sim(char(mdl), "ReturnWorkspaceOutputs", "on");
    [warnMsg, ~] = lastwarn;
    modelRun.warning = string(warnMsg);
    try
        modelRun.outputs = string(simOut.who);
    catch
        modelRun.outputs = strings(0, 1);
    end

    vm = extractTimeseries(simOut, "citt_vm");
    iclamp = extractTimeseries(simOut, "citt_clamp_current");
    amp = extractTimeseries(simOut, "citt_amplifier_output");
    adcRaw = extractTimeseries(simOut, "citt_adc_code_sequence");
    stateRaw = extractTimeseries(simOut, "citt_digital_control_state");
    satRaw = extractTimeseries(simOut, "citt_saturation_flags");
    cmdRaw = extractTimeseries(simOut, "citt_command_voltage");

    if isempty(vm.time) || isempty(vm.value)
        error("Benchmark03:NoVmOutput", "Simulink run completed but citt_vm was empty.");
    end

    t = vm.time(:);
    data.t = t;
    data.vm = vm.value(:);
    data.command = alignSignal(cmdRaw, t, commandWave(t, p));
    data.iclamp = alignSignal(iclamp, t, zeros(size(t)));
    data.vamp = alignSignal(amp, t, zeros(size(t)));
    adcV = alignSignal(adcRaw, t, data.vm);
    data.adc_code = voltageToAdcCode(adcV, p);
    data.digital_state = deriveState(t, data.vm, data.command, data.vamp, data.iclamp, p);
    if ~isempty(stateRaw.value)
        rawState = alignSignal(stateRaw, t, data.digital_state);
        if all(isfinite(rawState)) && numel(unique(round(rawState))) > 2
            data.digital_state = round(rawState);
        end
    end
    data.saturation_flag = deriveSaturation(data.vamp, data.iclamp, p);
    if ~isempty(satRaw.value)
        rawSat = alignSignal(satRaw, t, data.saturation_flag);
        if all(isfinite(rawSat)) && numel(rawSat) == numel(t)
            data.saturation_flag = double(rawSat(:) ~= 0);
        end
    end
    data.source = "Simulink/Simscape model run";
    modelRun.success = true;
catch ME
    data = struct();
    modelRun.success = false;
    modelRun.error = string(ME.message);
end
end

function data = simulateEducationalFallback(p)
dt = p.max_step;
t = (0:dt:p.t_stop).';
n = numel(t);
vm = zeros(n, 1);
vamp = zeros(n, 1);
iclamp = zeros(n, 1);
vm(1) = p.V_rest;
tauAmp = 1 / (2 * pi * p.amplifier_bandwidth_hz);
command = commandWave(t, p);
satFlag = zeros(n, 1);
for k = 2:n
    errorV = command(k - 1) - vm(k - 1) + p.input_offset;
    targetAmp = clamp(p.A_ol * errorV, p.V_rail_minus, p.V_rail_plus);
    vamp(k) = vamp(k - 1) + dt * (targetAmp - vamp(k - 1)) / max(tauAmp, dt);
    vamp(k) = clamp(vamp(k), p.V_rail_minus, p.V_rail_plus);

    rawCurrent = (vamp(k) - vm(k - 1)) / (p.R_e + p.R_series_output + p.output_resistance);
    iclamp(k) = clamp(rawCurrent, -p.I_limit, p.I_limit);
    ileak = (vm(k - 1) - p.E_leak) / p.R_m;
    inl = p.I_membrane_nonlinear_max ./ (1 + exp(-(vm(k - 1) - p.V_nonlinear_threshold) / p.V_nonlinear_slope));
    vm(k) = vm(k - 1) + dt * (iclamp(k) - ileak - inl) / p.C_m;
    satFlag(k) = abs(vamp(k)) >= p.saturation_voltage_threshold || abs(iclamp(k)) >= p.saturation_current_threshold;
end

data = struct();
data.t = t;
data.vm = vm;
data.command = command;
data.iclamp = iclamp;
data.vamp = vamp;
data.adc_code = voltageToAdcCode(vm, p);
data.digital_state = deriveState(t, vm, command, vamp, iclamp, p);
data.saturation_flag = satFlag;
data.source = "deterministic educational fallback";
end

function sweep = runSweep(p)
A = p.A_ol_values;
Re = p.R_e_values;
finalErrorMv = zeros(numel(Re), numel(A));
satMs = zeros(numel(Re), numel(A));
for i = 1:numel(Re)
    for j = 1:numel(A)
        q = p;
        q.R_e = Re(i);
        q.A_ol = A(j);
        q = benchmark03_educational_params(q);
        d = simulateEducationalFallback(q);
        m = computeMetrics(d, q);
        finalErrorMv(i, j) = m.final_tracking_error_mV;
        satMs(i, j) = m.saturation_duration_ms;
    end
end
sweep = struct();
sweep.A_ol_values = A;
sweep.R_e_values = Re;
sweep.final_tracking_error_mV = finalErrorMv;
sweep.saturation_duration_ms = satMs;
end

function faults = runFaultCases(p)
base = computeMetrics(simulateEducationalFallback(p), p);
rows = struct("id", {}, "expected_effect", {}, "settling_time_ms", {}, ...
    "final_tracking_error_mV", {}, "overshoot_percent", {}, "saturation_duration_ms", {});
for i = 1:numel(p.fault_cases)
    f = p.fault_cases(i);
    q = p;
    q.(char(f.parameter)) = f.value;
    if f.id == "low_adc_rate"
        q.fs = 500;
    end
    q = benchmark03_educational_params(q);
    m = computeMetrics(simulateEducationalFallback(q), q);
    rows(end + 1) = struct( ...
        "id", string(f.id), ...
        "expected_effect", string(f.expected_effect), ...
        "settling_time_ms", m.settling_time_ms, ...
        "final_tracking_error_mV", m.final_tracking_error_mV, ...
        "overshoot_percent", m.overshoot_percent, ...
        "saturation_duration_ms", m.saturation_duration_ms); %#ok<AGROW>
end
faults = struct();
faults.baseline = base;
faults.rows = rows;
end

function metrics = computeMetrics(data, p)
t = data.t(:);
vm = data.vm(:);
cmd = data.command(:);
err = vm - cmd;
after = t >= p.command_step_time;
finalErr = vm(end) - p.V_cmd_final;
delta = p.V_cmd_final - p.V_cmd_initial;
if delta >= 0
    overshoot = max(0, max(vm(after)) - p.V_cmd_final) / max(abs(delta), eps) * 100;
else
    overshoot = max(0, p.V_cmd_final - min(vm(after))) / max(abs(delta), eps) * 100;
end
settlingTime = NaN;
if any(after)
    idx = find(after);
    holdSamples = max(1, round(p.digital_settled_hold_time / median(diff(t))));
    good = abs(err) <= p.digital_settled_threshold;
    for k = idx(1):numel(t)
        last = min(numel(t), k + holdSamples - 1);
        if all(good(k:last))
            settlingTime = t(k) - p.command_step_time;
            break
        end
    end
end
sat = deriveSaturation(data.vamp(:), data.iclamp(:), p);
metrics = struct();
metrics.settling_time_ms = settlingTime * 1e3;
metrics.overshoot_percent = overshoot;
metrics.final_tracking_error_mV = finalErr * 1e3;
metrics.saturation_duration_ms = sum(sat ~= 0) * median(diff(t)) * 1e3;
metrics.saturation_duration_ms = min(metrics.saturation_duration_ms, (t(end) - t(1)) * 1e3);
metrics.max_abs_clamp_current_nA = max(abs(data.iclamp(:))) * 1e9;
metrics.max_abs_amplifier_output_V = max(abs(data.vamp(:)));
metrics.adc_code_min = min(data.adc_code(:));
metrics.adc_code_max = max(data.adc_code(:));
end

function writePlots(plotDirs, data, sweep, faults, p)
for i = 1:numel(plotDirs)
    d = plotDirs(i);
    plotFullTimeline(d, data, p);
    plotMembraneCurrent(d, data, p);
    plotAmplifierSaturation(d, data, p);
    plotAdcLogic(d, data, p);
    plotStateTrace(d, data);
    plotSweep(d, sweep);
    plotFaults(d, faults);
end
end

function plotFullTimeline(plotDir, data, p)
fig = makeFigure("Mixed Signal Full Timeline");
tMs = data.t * 1e3;
tiledlayout(5, 1, "TileSpacing", "compact", "Padding", "compact");
nexttile; plot(tMs, data.command * 1e3, "k--", tMs, data.vm * 1e3, "Color", monkGreen(), "LineWidth", 1.5); grid on; ylabel("mV"); legend("V_{cmd}", "V_m", "Location", "best"); title("Closed-loop transient (educational scaled Simscape run)");
nexttile; plot(tMs, data.iclamp * 1e9, "Color", [0.05 0.25 0.55], "LineWidth", 1.2); yline(p.I_limit * 1e9, "r--"); yline(-p.I_limit * 1e9, "r--"); grid on; ylabel("nA");
nexttile; plot(tMs, data.vamp, "Color", [0.45 0.16 0.08], "LineWidth", 1.2); yline(p.V_rail_plus, "r--"); yline(p.V_rail_minus, "r--"); grid on; ylabel("V");
nexttile; stairs(tMs, data.adc_code, "Color", [0.28 0.22 0.55], "LineWidth", 1.1); grid on; ylabel("ADC code");
nexttile; stairs(tMs, data.digital_state, "Color", monkGreen(), "LineWidth", 1.1); hold on; stairs(tMs, data.saturation_flag * 5, "r:", "LineWidth", 1.1); grid on; ylabel("state"); xlabel("time (ms)");
savePlot(fig, plotDir, "mixed_signal_full_timeline.png");
end

function plotMembraneCurrent(plotDir, data, p)
fig = makeFigure("Membrane Voltage and Clamp Current");
yyaxis left; plot(data.t * 1e3, data.command * 1e3, "k--", data.t * 1e3, data.vm * 1e3, "Color", monkGreen(), "LineWidth", 1.7); ylabel("Vm / command (mV)");
yyaxis right; plot(data.t * 1e3, data.iclamp * 1e9, "Color", [0.05 0.25 0.55], "LineWidth", 1.2); ylabel("clamp current (nA)");
xline(p.command_step_time * 1e3, ":", "command step"); grid on; xlabel("time (ms)"); title("Membrane voltage recovery and clamp current");
savePlot(fig, plotDir, "membrane_voltage_and_clamp_current.png");
end

function plotAmplifierSaturation(plotDir, data, p)
fig = makeFigure("Amplifier Saturation");
tMs = data.t * 1e3;
tiledlayout(2, 1, "TileSpacing", "compact", "Padding", "compact");
nexttile; plot(tMs, data.vamp, "Color", [0.45 0.16 0.08], "LineWidth", 1.4); yline(p.V_rail_plus, "r--", "+ rail"); yline(p.V_rail_minus, "r--", "- rail"); grid on; ylabel("V_{amp} (V)"); title("Rail and current-limit evidence");
nexttile; plot(tMs, data.iclamp * 1e9, "Color", [0.05 0.25 0.55], "LineWidth", 1.4); yline(p.I_limit * 1e9, "r--", "+ limit"); yline(-p.I_limit * 1e9, "r--", "- limit"); hold on; area(tMs, data.saturation_flag * p.I_limit * 1e9, "FaceColor", [0.8 0.1 0.1], "FaceAlpha", 0.12, "EdgeColor", "none"); grid on; ylabel("I_{clamp} (nA)"); xlabel("time (ms)");
savePlot(fig, plotDir, "amplifier_saturation.png");
end

function plotAdcLogic(plotDir, data, p)
fig = makeFigure("ADC Codes and Digital Logic");
tMs = data.t * 1e3;
tiledlayout(3, 1, "TileSpacing", "compact", "Padding", "compact");
nexttile; stairs(tMs, data.adc_code, "Color", [0.28 0.22 0.55], "LineWidth", 1.2); grid on; ylabel("ADC code"); title(sprintf("ADC: %d bit, fs = %.0f Hz, LSB = %.3f mV", p.adc_bits, p.fs, p.adc_lsb * 1e3));
nexttile; stairs(tMs, data.digital_state, "Color", monkGreen(), "LineWidth", 1.2); grid on; ylabel("state"); yticks(0:4); yticklabels(["idle","acquire","clamp","sat","settled"]);
nexttile; stairs(tMs, data.saturation_flag, "r", "LineWidth", 1.2); ylim([-0.1 1.1]); grid on; ylabel("sat flag"); xlabel("time (ms)");
savePlot(fig, plotDir, "adc_codes_and_digital_logic.png");
end

function plotStateTrace(plotDir, data)
fig = makeFigure("Digital State Machine Trace");
stairs(data.t * 1e3, data.digital_state, "Color", monkGreen(), "LineWidth", 1.8); hold on;
stairs(data.t * 1e3, data.saturation_flag * 3, "r--", "LineWidth", 1.2);
grid on; xlabel("time (ms)"); ylabel("state"); yticks(0:4); yticklabels(["idle","acquire","clamp","sat","settled"]);
title("Digital state machine trace derived from ADC error and saturation flags");
legend("digital state", "saturation flag overlay", "Location", "best");
savePlot(fig, plotDir, "digital_state_machine_trace.png");
end

function plotSweep(plotDir, sweep)
fig = makeFigure("Parameter Sweep Heatmap");
tiledlayout(1, 2, "TileSpacing", "compact", "Padding", "compact");
nexttile; imagesc(log10(sweep.A_ol_values), sweep.R_e_values / 1e6, sweep.final_tracking_error_mV); colorbar; xlabel("log10(A_{ol})"); ylabel("R_e (Mohm)"); title("Final tracking error (mV)"); set(gca, "YDir", "normal");
nexttile; imagesc(log10(sweep.A_ol_values), sweep.R_e_values / 1e6, sweep.saturation_duration_ms); colorbar; xlabel("log10(A_{ol})"); ylabel("R_e (Mohm)"); title("Saturation duration (ms)"); set(gca, "YDir", "normal");
savePlot(fig, plotDir, "parameter_sweep_heatmap.png");
end

function plotFaults(plotDir, faults)
fig = makeFigure("Fault Injection Summary");
names = string({faults.rows.id});
settling = [faults.rows.settling_time_ms];
errorMv = abs([faults.rows.final_tracking_error_mV]);
satMs = [faults.rows.saturation_duration_ms];
bar(categorical(names), [settling(:), errorMv(:), satMs(:)]);
grid on; ylabel("metric value"); title("Fault injection summary from educational scaled simulation");
legend("settling time (ms)", "|final error| (mV)", "sat duration (ms)", "Location", "best");
xtickangle(25);
set(gca, "TickLabelInterpreter", "none");
savePlot(fig, plotDir, "fault_injection_summary.png");
end

function ts = extractTimeseries(simOut, name)
ts = struct("time", [], "value", []);
try
    value = simOut.get(name);
catch
    try
        value = evalin("base", name);
    catch
        return
    end
end
if isa(value, "timeseries")
    ts.time = value.Time(:);
    raw = squeeze(value.Data);
    if ismatrix(raw) && size(raw, 1) == numel(ts.time) && size(raw, 2) > 1
        raw = max(abs(raw), [], 2);
    end
    ts.value = double(raw(:));
elseif istimetable(value)
    ts.time = seconds(value.Properties.RowTimes - value.Properties.RowTimes(1));
    ts.value = double(value{:, 1});
elseif isnumeric(value)
    ts.time = (0:numel(value)-1).';
    ts.value = double(value(:));
end
end

function aligned = alignSignal(ts, t, defaultValue)
if isempty(ts.time) || isempty(ts.value)
    aligned = defaultValue(:);
    return
end
aligned = interp1(ts.time(:), ts.value(:), t(:), "previous", "extrap");
if any(~isfinite(aligned))
    aligned = interp1(ts.time(:), ts.value(:), t(:), "linear", "extrap");
end
end

function y = commandWave(t, p)
y = p.V_cmd_initial + (t >= p.command_step_time) * (p.V_cmd_final - p.V_cmd_initial);
end

function code = voltageToAdcCode(v, p)
code = round((v - p.adc_input_range(1)) / p.adc_lsb);
code = max(0, min(2^p.adc_bits - 1, code));
end

function state = deriveState(t, vm, cmd, vamp, iclamp, p)
state = zeros(size(t));
state(t >= p.command_step_time) = 1;
err = abs(vm - cmd);
state(t >= p.command_step_time & err > p.digital_settled_threshold) = 2;
sat = deriveSaturation(vamp, iclamp, p);
state(sat ~= 0) = 3;
state(t >= p.command_step_time & err <= p.digital_settled_threshold & sat == 0) = 4;
end

function sat = deriveSaturation(vamp, iclamp, p)
sat = double(abs(vamp) >= p.saturation_voltage_threshold | abs(iclamp) >= p.saturation_current_threshold);
end

function y = clamp(x, lo, hi)
y = min(max(x, lo), hi);
end

function fig = makeFigure(name)
fig = figure("Visible", "off", "Color", "w", "Name", name, "Position", [100 100 1400 900]);
end

function c = monkGreen()
c = [0.12 0.50 0.31];
end

function savePlot(fig, plotDir, name)
exportgraphics(fig, char(fullfile(plotDir, name)), "Resolution", 180);
close(fig);
end

function names = requiredPlotNames()
names = [
    "mixed_signal_full_timeline.png"
    "membrane_voltage_and_clamp_current.png"
    "amplifier_saturation.png"
    "adc_codes_and_digital_logic.png"
    "digital_state_machine_trace.png"
    "parameter_sweep_heatmap.png"
    "fault_injection_summary.png"
];
end

function text = renderReport(result)
m = result.metrics;
lines = strings(0, 1);
lines(end + 1) = "# Benchmark 3 Simulation Report";
lines(end + 1) = "";
lines(end + 1) = "- Parameter set: " + string(result.parameter_set_label);
lines(end + 1) = "- Warning: " + string(result.parameter_set_warning);
lines(end + 1) = "- Simulation source: " + string(result.simulation_source);
lines(end + 1) = "- Model: `" + string(result.model_path) + "`";
lines(end + 1) = "";
lines(end + 1) = "## Metrics";
lines(end + 1) = "";
lines(end + 1) = "- Settling time: " + metricText(m.settling_time_ms, "ms");
lines(end + 1) = "- Overshoot: " + metricText(m.overshoot_percent, "%");
lines(end + 1) = "- Final tracking error: " + metricText(m.final_tracking_error_mV, "mV");
lines(end + 1) = "- Saturation duration: " + metricText(m.saturation_duration_ms, "ms");
lines(end + 1) = "- Max clamp current: " + metricText(m.max_abs_clamp_current_nA, "nA");
lines(end + 1) = "- Max amplifier output: " + metricText(m.max_abs_amplifier_output_V, "V");
lines(end + 1) = "";
lines(end + 1) = "## Interpretation";
lines(end + 1) = "";
if isfield(result.model_run, "warning") && strlength(string(result.model_run.warning)) > 0
    lines(end + 1) = "- Model warning: " + string(result.model_run.warning);
end
lines(end + 1) = "- The nominal generated model does not settle in the 60 ms window and stays at the rail/current limit. This is device-performance evidence and a model limitation, not a clinical claim.";
lines(end + 1) = "- Parameter sweep and fault-injection plots use the same educational scaled equations deterministically for comparison speed; the nominal timeline plots are from the Simulink/Simscape model run.";
lines(end + 1) = "";
lines(end + 1) = "## Required Plots";
lines(end + 1) = "";
for i = 1:numel(result.required_plots)
    lines(end + 1) = "- `" + result.required_plots(i) + "`"; %#ok<AGROW>
end
if ~result.model_run.success
    lines = [lines; ""; "## Model Run Limitation"; ""; "The Simulink/Simscape model was parameterized, but `sim()` did not complete. The generated plots use the deterministic educational fallback and are labeled as such. Error: " + result.model_run.error];
end
text = strjoin(lines, newline);
end

function text = metricText(value, unit)
if isempty(value) || ~isfinite(value)
    text = "not settled";
    if unit ~= "ms"
        text = "not finite";
    end
else
    text = sprintf("%.4g %s", value, unit);
end
end

function updateRunNotes(benchDir, result)
notes = [
    "# CiTT Run Notes: Closed-Loop Neural Clamp With Nonideal Amplifier, ADC, and Digital Control Logic"
    ""
    "manual_arrangement: completed-by-user"
    "simulation_source: " + result.simulation_source
    "parameter_set: educational scaled benchmark parameters, not a validated axon or patient model"
    "timestamp: " + string(datetime("now", "Format", "yyyy-MM-dd HH:mm:ss z"))
    ""
    "Functional evidence now includes transient plots, ADC/digital logic plots, parameter sweep, and fault injection summary."
    "If the Simulink/Simscape model cannot execute in the local MATLAB install, the deterministic educational fallback is explicitly labeled in the report and plots are not represented as medical-use validation."
];
writeText(fullfile(benchDir, "citt_run_notes.md"), strjoin(notes, newline));
comparison = [
    "# Comparison: Mixed-Signal Neural Clamp"
    ""
    "LLM-only text is not enough for this benchmark. The requested outputs depend on transient dynamics, saturation timing, ADC quantization, digital state transitions, parameter sweeps, and fault injection."
    ""
    "CiTT evidence now includes an educational scaled parameter set and executable simulation outputs. The parameter set is explicitly not a clinically validated axon model; it is chosen to make device-performance and limitation behavior visible for teaching and product evaluation."
    ""
    "Key proof artifacts: `mixed_signal_full_timeline.png`, `amplifier_saturation.png`, `adc_codes_and_digital_logic.png`, `parameter_sweep_heatmap.png`, and `fault_injection_summary.png`."
];
writeText(fullfile(benchDir, "comparison.md"), strjoin(comparison, newline));
end

function value = optionString(options, fieldName, defaultValue)
if isstruct(options) && isfield(options, fieldName)
    value = string(options.(fieldName));
else
    value = string(defaultValue);
end
end

function ensureDir(path)
if exist(path, "dir") ~= 7
    mkdir(path);
end
end

function writeJson(path, value)
writeText(path, string(citt.util.jsonEncode(value)));
end

function writeText(path, text)
[folder, ~, ~] = fileparts(string(path));
if strlength(folder) > 0 && exist(folder, "dir") ~= 7
    mkdir(folder);
end
fid = fopen(char(string(path)), "w");
if fid < 0
    error("Benchmark03:WriteFailed", "Could not write %s.", string(path));
end
cleanup = onCleanup(@() fclose(fid));
text = string(text);
text(ismissing(text)) = "";
fprintf(fid, "%s", char(text));
end
